// Element seçmə nümunəsi
const heading = document.getElementById('myHeading');
console.log(heading.textContent); // ID-si 'myHeading' olan elementin mətnini konsola yazdırır

const firstParagraph = document.querySelector('.paragraph');
console.log(firstParagraph.textContent); // İlk '.paragraph' sinifli elementin mətnini konsola yazdırır

const allParagraphs = document.querySelectorAll('.paragraph');
console.log(allParagraphs.length); // '.paragraph' sinifli elementlərin sayını konsola yazdırır

// Məzmun dəyişmə nümunəsi
const heading = document.getElementById('myHeading');
heading.textContent = 'Yeni Başlıq'; // Başlığı dəyişir

const div = document.querySelector('.container');
div.innerHTML = '<p>Yeni paraqraf</p>'; // HTML məzmunu əlavə edir

// Yeni element əlavə etmə nümunəsi
const newParagraph = document.createElement('p');
newParagraph.textContent = 'Bu yeni paraqrafdır';

const container = document.querySelector('.container');
container.appendChild(newParagraph); // Yeni paraqrafı konteynerə əlavə edir

// Hadisə idarəetmə nümunəsi
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  console.log('Düyməyə klik olundu!');
});

// Səhvə yol açan nümunə
const element = document.getElementById('wrongId');
element.textContent = 'Dəyişiklik'; // TypeError: Cannot set property 'textContent' of null

// Düzgün yol
if (element) {
  element.textContent = 'Dəyişiklik';
} else {
  console.log('Element tapılmadı');
}

// Selecting elements example
const heading = document.getElementById('myHeading');
console.log(heading.textContent); // Logs the text of the element with ID 'myHeading'

const firstParagraph = document.querySelector('.paragraph');
console.log(firstParagraph.textContent); // Logs the text of the first '.paragraph' element

const allParagraphs = document.querySelectorAll('.paragraph');
console.log(allParagraphs.length); // Logs the number of '.paragraph' elements

// Modifying content example
const heading = document.getElementById('myHeading');
heading.textContent = 'New Heading'; // Changes the heading text

const div = document.querySelector('.container');
div.innerHTML = '<p>New paragraph</p>'; // Adds new HTML content

// Creating and adding elements example
const newParagraph = document.createElement('p');
newParagraph.textContent = 'This is a new paragraph';

const container = document.querySelector('.container');
container.appendChild(newParagraph); // Adds the new paragraph to the container

// Event handling example
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  console.log('Button clicked!');
});

// Error-prone example
const element = document.getElementById('wrongId');
element.textContent = 'Change'; // TypeError: Cannot set property 'textContent' of null

// Correct approach
if (element) {
  element.textContent = 'Change';
} else {
  console.log('Element not found');
}

// Пример выбора элементов
const heading = document.getElementById('myHeading');
console.log(heading.textContent); // Выводит текст элемента с ID 'myHeading'

const firstParagraph = document.querySelector('.paragraph');
console.log(firstParagraph.textContent); // Выводит текст первого элемента с классом '.paragraph'

const allParagraphs = document.querySelectorAll('.paragraph');
console.log(allParagraphs.length); // Выводит количество элементов с классом '.paragraph'

// Пример изменения содержимого
const heading = document.getElementById('myHeading');
heading.textContent = 'Новый заголовок'; // Изменяет текст заголовка

const div = document.querySelector('.container');
div.innerHTML = '<p>Новый параграф</p>'; // Добавляет новый HTML-контент

// Пример создания и добавления элементов
const newParagraph = document.createElement('p');
newParagraph.textContent = 'Это новый параграф';

const container = document.querySelector('.container');
container.appendChild(newParagraph); // Добавляет новый параграф в контейнер

// Пример обработки событий
const button = document.querySelector('#myButton');
button.addEventListener('click', () => {
  console.log('Кнопка нажата!');
});

// Пример с ошибкой
const element = document.getElementById('wrongId');
element.textContent = 'Изменение'; // TypeError: Cannot set property 'textContent' of null

// Правильный подход
if (element) {
  element.textContent = 'Изменение';
} else {
  console.log('Элемент не найден');
}
